def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 2, -2):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    priority += val * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 3))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4.5) * 2.5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 14):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 1.2)
            priority = (s * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if i % 2 == 0:
                for w in range(3):
                    priority += np.cos(ratio * i * (w+1)) * 0.2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 11):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.exp(-n / 10)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.05) * ((ratio - 1) ** m) / (m * 1.1)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * ratio * 1.3)
            priority = s
            if (i * int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 3) + 1.7)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 3.2) * np.cos(k * ratio * 2.3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 3 == 1:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 11):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 9):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2.5 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx_offset in range(1, 5):
            if (i + idx_offset) % 4 == 0:
                priority += np.sin(ratio * (i + idx_offset) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx_offset) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 5 == 0:
            for z in range(2, 7):
                priority += np.sin(ratio * i * z * 0.5) * (z / 10)
        priorities[i] = priority
    return priorities
